"use strict";exports.id=6817,exports.ids=[6817],exports.modules={46817:a=>{a.exports=JSON.parse('{"cookies":{"title":"Politique en mati\xe8re de cookies","lastUpdated":"Derni\xe8re mise \xe0 jour :","sections":{"what":{"title":"1. Qu\'est-ce que les cookies ?","content":"Les cookies sont de petits fichiers texte plac\xe9s sur votre ordinateur ou votre appareil mobile lorsque vous visitez un site Web. Ils sont largement utilis\xe9s pour rendre les sites Web plus efficaces et fournir des informations aux propri\xe9taires de sites Web."},"how":{"title":"2. Comment nous utilisons les cookies","intro":"Wayfera utilise des cookies pour :","items":["M\xe9moriser vos pr\xe9f\xe9rences et param\xe8tres","Vous maintenir connect\xe9 \xe0 votre compte","Comprendre comment vous utilisez notre site Web","Am\xe9liorer nos services et l\'exp\xe9rience utilisateur","Fournir du contenu et des recommandations personnalis\xe9s","Analyser le trafic et les performances du site Web"]},"types":{"title":"3. Types de cookies que nous utilisons","essential":{"title":"Cookies essentiels","description":"Ces cookies sont n\xe9cessaires au fonctionnement correct du site Web. Ils activent les fonctions de base telles que la navigation entre les pages, l\'acc\xe8s aux zones s\xe9curis\xe9es et les processus de r\xe9servation.","duration":"Session ou jusqu\'\xe0 1 an"},"performance":{"title":"Cookies de performance","description":"Ces cookies collectent des informations sur la fa\xe7on dont les visiteurs utilisent notre site Web, tels que les pages les plus fr\xe9quemment consult\xe9es. Cela nous aide \xe0 am\xe9liorer les performances de notre site Web.","duration":"Jusqu\'\xe0 2 ans"},"functionality":{"title":"Cookies de fonctionnalit\xe9","description":"Ces cookies permettent au site Web de m\xe9moriser les choix que vous faites (tels que la pr\xe9f\xe9rence de langue, la devise ou la r\xe9gion) et de fournir des fonctionnalit\xe9s am\xe9lior\xe9es et personnalis\xe9es.","duration":"Jusqu\'\xe0 1 an"},"targeting":{"title":"Cookies de ciblage/publicit\xe9","description":"Ces cookies sont utilis\xe9s pour vous diffuser des publicit\xe9s plus pertinentes et adapt\xe9es \xe0 vos int\xe9r\xeats. Ils aident \xe9galement \xe0 mesurer l\'efficacit\xe9 des campagnes publicitaires.","duration":"Jusqu\'\xe0 2 ans"}},"third_party":{"title":"4. Cookies de tiers","intro":"Nous pouvons utiliser des services tiers qui d\xe9finissent \xe9galement des cookies sur votre appareil. Ceux-ci comprennent :","items":["Google Analytics : pour analyser le trafic et le comportement des utilisateurs du site Web","Plates-formes de m\xe9dias sociaux : pour activer les fonctionnalit\xe9s de partage social","Processeurs de paiement : pour faciliter les transactions s\xe9curis\xe9es","R\xe9seaux publicitaires : pour afficher des publicit\xe9s pertinentes"]},"managing":{"title":"5. Gestion des cookies","intro":"Vous avez le droit de d\xe9cider si vous acceptez ou refusez les cookies. Vous pouvez exercer vos pr\xe9f\xe9rences en mati\xe8re de cookies en :","items":["Utilisant notre banneau de consentement aux cookies lors de votre premi\xe8re visite sur notre site Web","Ajustant les param\xe8tres de votre navigateur pour refuser les cookies","Supprimant les cookies qui ont d\xe9j\xe0 \xe9t\xe9 d\xe9finis"],"note":"Veuillez noter que si vous choisissez de bloquer ou de supprimer des cookies, certaines fonctionnalit\xe9s de notre site Web peuvent ne pas fonctionner correctement."},"browser":{"title":"6. Instructions sp\xe9cifiques au navigateur","intro":"Pour g\xe9rer les cookies dans votre navigateur :","items":["Chrome : Param\xe8tres → Confidentialit\xe9 et s\xe9curit\xe9 → Cookies et donn\xe9es de site","Firefox : Options → Confidentialit\xe9 et s\xe9curit\xe9 → Cookies et donn\xe9es de site","Safari : Pr\xe9f\xe9rences → Confidentialit\xe9 → G\xe9rer les donn\xe9es du site Web","Edge : Param\xe8tres → Cookies et autorisations du site → Cookies et donn\xe9es du site"]},"storage":{"title":"7. Stockage local et stockage de session","intro":"En plus des cookies, nous utilisons les technologies de stockage du navigateur (localStorage et sessionStorage) pour :","items":["Stocker les pr\xe9f\xe9rences et les param\xe8tres de l\'utilisateur","Mettre en cache les donn\xe9es pour am\xe9liorer les performances","Maintenir les informations de session","Vous rappeler vos destinations pr\xe9f\xe9r\xe9es"]},"dnt":{"title":"8. Signaux de non-suivi","content":"Certains navigateurs incluent une fonctionnalit\xe9 \\"Ne pas me suivre\\" (DNT) qui signale aux sites Web que vous ne souhaitez pas que votre activit\xe9 en ligne soit suivie. Nous ne r\xe9pondons actuellement pas aux signaux DNT, mais nous respectons vos choix en mati\xe8re de confidentialit\xe9 et vous proposons des options de gestion des cookies."},"updates":{"title":"9. Mises \xe0 jour de cette politique","content":"Nous pouvons mettre \xe0 jour cette politique en mati\xe8re de cookies de temps \xe0 autre pour refl\xe9ter les changements technologiques, l\xe9gislatifs ou nos pratiques commerciales. Nous vous informerons de tout changement important en publiant la politique mise \xe0 jour sur notre site Web."},"contact":{"title":"10. Nous contacter","intro":"Si vous avez des questions sur notre utilisation des cookies, veuillez nous contacter :"}}},"privacy":{"title":"Politique de confidentialit\xe9","lastUpdated":"Derni\xe8re mise \xe0 jour :"},"terms":{"title":"Conditions de service","lastUpdated":"Derni\xe8re mise \xe0 jour :"}}')}};